import fs from 'node:fs';
import path from 'node:path';
import { CHATS_DATA_DIR, LEARNING_DATA_DIR, MEMORY_DATA_DIR, loadUserContext } from '../../config.js';

export interface MemoryRecord {
  namespace: string;
  key: string;
  value: unknown;
  tags?: string[];
  updated_at: string;
}

interface MemoryStore {
  records: MemoryRecord[];
}

interface LearningFileOverview {
  file: string;
  updated_at: string;
  bytes: number;
  preview: string;
}

interface ChatOverview {
  file: string;
  session_id: string;
  messages_count: number;
  updated_at: string;
  last_user: string;
  last_assistant: string;
}

export interface MemoryOverview {
  user_context_preview: string;
  profile_memory: unknown;
  stats: {
    learning_files: number;
    memory_records: number;
    chat_sessions: number;
  };
  learning_files: LearningFileOverview[];
  memory_records: MemoryRecord[];
  chats: ChatOverview[];
}

export class MemoryService {
  private memoryFile = path.join(MEMORY_DATA_DIR, 'memory_store.json');
  private profileFile = path.join(MEMORY_DATA_DIR, 'profile_memory.json');

  private sanitizeToken(input: string, fallback: string): string {
    const cleaned = String(input || '').trim().replace(/[^a-zA-Z0-9_.-]/g, '_').slice(0, 120);
    return cleaned || fallback;
  }

  private readStore(): MemoryStore {
    if (!fs.existsSync(this.memoryFile)) return { records: [] };
    try {
      return JSON.parse(fs.readFileSync(this.memoryFile, 'utf8')) as MemoryStore;
    } catch {
      return { records: [] };
    }
  }

  private writeStore(store: MemoryStore): void {
    fs.writeFileSync(this.memoryFile, JSON.stringify(store, null, 2), 'utf8');
  }

  private truncate(input: unknown, max = 400): string {
    const text = String(input || '').replace(/\s+/g, ' ').trim();
    return text.length > max ? `${text.slice(0, max)}...` : text;
  }

  private readJsonSafe<T>(filePath: string, fallback: T): T {
    try {
      return JSON.parse(fs.readFileSync(filePath, 'utf8')) as T;
    } catch {
      return fallback;
    }
  }

  upsert(input: { namespace?: string; key?: string; value: unknown; tags?: string[] }): MemoryRecord {
    const namespace = this.sanitizeToken(input.namespace || 'general', 'general');
    const key = this.sanitizeToken(input.key || 'entry', 'entry');

    const store = this.readStore();
    const now = new Date().toISOString();
    const next: MemoryRecord = {
      namespace,
      key,
      value: input.value,
      tags: Array.isArray(input.tags) ? input.tags.slice(0, 20) : undefined,
      updated_at: now,
    };

    const idx = store.records.findIndex((r) => r.namespace === namespace && r.key === key);
    if (idx >= 0) {
      store.records[idx] = next;
    } else {
      store.records.push(next);
    }

    this.writeStore(store);

    if (namespace === 'profile') {
      fs.writeFileSync(this.profileFile, JSON.stringify(next, null, 2), 'utf8');
    }

    return next;
  }

  profile(): { user_context: string; profile_memory: unknown; records_count: number; learning_files: string[] } {
    const store = this.readStore();
    const profileMemory = fs.existsSync(this.profileFile)
      ? JSON.parse(fs.readFileSync(this.profileFile, 'utf8'))
      : null;

    const learningFiles = fs.existsSync(LEARNING_DATA_DIR)
      ? fs.readdirSync(LEARNING_DATA_DIR).filter((f) => f.endsWith('.txt')).sort()
      : [];

    return {
      user_context: loadUserContext(),
      profile_memory: profileMemory,
      records_count: store.records.length,
      learning_files: learningFiles,
    };
  }

  overview(): MemoryOverview {
    const store = this.readStore();
    const profileMemory = fs.existsSync(this.profileFile)
      ? this.readJsonSafe(this.profileFile, null)
      : null;

    const learningFiles: LearningFileOverview[] = fs.existsSync(LEARNING_DATA_DIR)
      ? fs.readdirSync(LEARNING_DATA_DIR)
        .filter((f) => f.endsWith('.txt'))
        .map((file) => {
          const filePath = path.join(LEARNING_DATA_DIR, file);
          const stat = fs.statSync(filePath);
          const raw = fs.readFileSync(filePath, 'utf8');
          return {
            file,
            updated_at: stat.mtime.toISOString(),
            bytes: stat.size,
            preview: this.truncate(raw, 520),
          };
        })
        .sort((a, b) => b.updated_at.localeCompare(a.updated_at))
      : [];

    const chats: ChatOverview[] = fs.existsSync(CHATS_DATA_DIR)
      ? fs.readdirSync(CHATS_DATA_DIR)
        .filter((f) => f.endsWith('.json'))
        .map((file) => {
          const filePath = path.join(CHATS_DATA_DIR, file);
          const stat = fs.statSync(filePath);
          const payload = this.readJsonSafe<{ session_id?: string; messages?: Array<{ role?: string; content?: unknown }> }>(
            filePath,
            {},
          );
          const messages = Array.isArray(payload.messages) ? payload.messages : [];
          const users = messages.filter((m) => m.role === 'user');
          const assistants = messages.filter((m) => m.role === 'assistant');
          return {
            file,
            session_id: String(payload.session_id || '').trim() || file.replace(/^chat_/, '').replace(/\.json$/, ''),
            messages_count: messages.length,
            updated_at: stat.mtime.toISOString(),
            last_user: this.truncate(users.at(-1)?.content || '', 180),
            last_assistant: this.truncate(assistants.at(-1)?.content || '', 180),
          };
        })
        .sort((a, b) => b.updated_at.localeCompare(a.updated_at))
        .slice(0, 25)
      : [];

    return {
      user_context_preview: this.truncate(loadUserContext(), 1500),
      profile_memory: profileMemory,
      stats: {
        learning_files: learningFiles.length,
        memory_records: store.records.length,
        chat_sessions: chats.length,
      },
      learning_files: learningFiles,
      memory_records: store.records
        .slice()
        .sort((a, b) => b.updated_at.localeCompare(a.updated_at))
        .slice(0, 50),
      chats,
    };
  }
}

